{
  "name": "AI Festive Lens",
  "description": "Transform your casual selfies into stunning, professional-grade festival greeting cards using Gemini's advanced image editing capabilities. Supports multiple global festivals and both English and Traditional Chinese.",
  "requestFramePermissions": [
    "camera"
  ]
}

export enum Language {
  EN = 'EN',
  ZH = 'ZH'
}

export interface Festival {
  id: string;
  nameEn: string;
  nameZh: string;
  prompt: string;
  icon: string;
  color: string;
}

export interface AppState {
  image: string | null;
  selectedFestivalId: string | null;
  language: Language;
  isGenerating: boolean;
  resultImage: string | null;
  error: string | null;
}

import { GoogleGenAI } from "@google/genai";

export async function generateFestivalCard(
  base64Image: string,
  festivalPrompt: string
): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Clean base64 string
  const cleanBase64 = base64Image.split(',')[1] || base64Image;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            inlineData: {
              data: cleanBase64,
              mimeType: 'image/jpeg',
            },
          },
          {
            text: `Please edit this image to create a high-quality festival greeting card. ${festivalPrompt} Keep the person's face and basic features recognizable but style them appropriately for the festival. The result should be a single, beautiful, polished image suitable for sharing as a greeting card.`,
          },
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: "3:4", // Better for mobile greeting cards
        }
      }
    });

    if (!response.candidates?.[0]?.content?.parts) {
      throw new Error('No image generated');
    }

    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }

    throw new Error('Image data not found in response');
  } catch (error) {
    console.error('Error generating festival card:', error);
    throw error;
  }
}

