import React, { useState, useRef, useCallback } from 'react';
import { Language, AppState } from './types';
import { FESTIVALS, TRANSLATIONS } from './constants';
import { LanguageToggle } from './components/LanguageToggle';
import { FestivalCard } from './components/FestivalCard';
import { generateFestivalCard } from './services/gemini';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    image: null,
    selectedFestivalId: null,
    language: Language.ZH,
    isGenerating: false,
    resultImage: null,
    error: null,
  });

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleLanguageToggle = (lang: Language) => {
    setState(prev => ({ ...prev, language: lang }));
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setState(prev => ({ 
          ...prev, 
          image: reader.result as string,
          resultImage: null,
          error: null
        }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleGenerate = async () => {
    if (!state.image || !state.selectedFestivalId) return;

    const festival = FESTIVALS.find(f => f.id === state.selectedFestivalId);
    if (!festival) return;

    setState(prev => ({ ...prev, isGenerating: true, error: null }));

    try {
      const result = await generateFestivalCard(state.image, festival.prompt);
      setState(prev => ({ ...prev, resultImage: result, isGenerating: false }));
    } catch (err) {
      setState(prev => ({ 
        ...prev, 
        isGenerating: false, 
        error: TRANSLATIONS[state.language].error 
      }));
    }
  };

  const handleReset = () => {
    setState(prev => ({
      ...prev,
      image: null,
      selectedFestivalId: null,
      resultImage: null,
      error: null
    }));
  };

  const currentT = TRANSLATIONS[state.language];

