        </h1>
        <p className="text-lg text-slate-600 font-light">
          {currentT.subtitle}
        </p>
      </header>

      <main className="w-full max-w-4xl bg-white/40 backdrop-blur-xl rounded-3xl p-6 md:p-10 shadow-xl border border-white/50">

