           <div className={`flex flex-col items-center ${state.image ? 'text-green-600' : 'text-slate-400'}`}>
              <div className={`w-8 h-8 rounded-full flex items-center justify-center mb-1 text-xs font-bold ${state.image ? 'bg-green-100' : 'bg-slate-200'}`}>1</div>
              <span className="text-[10px] uppercase tracking-wider font-bold whitespace-nowrap">{currentT.step1}</span>
           </div>
           <div className="h-[2px] w-full bg-slate-200 min-w-[20px]"></div>
           <div className={`flex flex-col items-center ${state.selectedFestivalId ? 'text-green-600' : 'text-slate-400'}`}>
              <div className={`w-8 h-8 rounded-full flex items-center justify-center mb-1 text-xs font-bold ${state.selectedFestivalId ? 'bg-green-100' : 'bg-slate-200'}`}>2</div>
              <span className="text-[10px] uppercase tracking-wider font-bold whitespace-nowrap">{currentT.step2}</span>
           </div>
           <div className="h-[2px] w-full bg-slate-200 min-w-[20px]"></div>
           <div className={`flex flex-col items-center ${state.resultImage ? 'text-green-600' : 'text-slate-400'}`}>
              <div className={`w-8 h-8 rounded-full flex items-center justify-center mb-1 text-xs font-bold ${state.resultImage ? 'bg-green-100' : 'bg-slate-200'}`}>3</div>
              <span className="text-[10px] uppercase tracking-wider font-bold whitespace-nowrap">{currentT.step3}</span>
           </div>
        </div>

        <div className="grid md:grid-cols-2 gap-10">

