                  {state.error}
                </div>
              )}
            </div>
          </div>
        </div>
      </main>

      <footer className="mt-16 text-slate-400 text-sm flex flex-col items-center gap-4">
        <p>© 2024 AI Festive Lens • Powered by Gemini 2.5</p>
        <div className="flex gap-6 opacity-60">
          <span>Privacy Policy</span>
          <span>Terms of Use</span>
          <span>Contact</span>
        </div>
      </footer>

      <style>{`
        @keyframes loading {
          0% { transform: translateX(-100%); }
          100% { transform: translateX(200%); }
        }
      `}</style>
    </div>
  );
};

export default App;

