export enum Language {
  EN = 'EN',
  ZH = 'ZH'
}

export interface Festival {
  id: string;
  nameEn: string;
  nameZh: string;
  greetingEn: string;
  greetingZh: string;
  prompt: string;
  icon: string;
  color: string;
}

export interface AppState {
  image: string | null;
  selectedFestivalId: string | null;
  language: Language;
  isGenerating: boolean;
  resultImage: string | null;
  error: string | null;
}

import { GoogleGenAI } from "@google/genai";

export async function generateFestivalCard(
  base64Image: string,
  festivalPrompt: string,
  greetingEn: string,
  greetingZh: string
): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const cleanBase64 = base64Image.split(',')[1] || base64Image;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            inlineData: {
              data: cleanBase64,
              mimeType: 'image/jpeg',
            },
          },
          {
            text: `
              Transform this image into a professional, high-quality festival greeting card. 

              THEME: ${festivalPrompt}

              REQUIREMENTS:
              1. SUBJECTS: Keep all people and pets (dogs, cats, etc.) from the original image. Maintain their basic facial features and positions but style their clothing and accessories to match the festival theme.
              2. OBJECT REMOVAL: Do NOT include any mundane office items, folders, boxes, or shopping bags held by the people. Replace these items with festive props (like a lantern, a gift box, or a decorative ornament) or have the people pose naturally without them.
              3. TEXT OVERLAY: Artistically render the following greeting text onto the card in a beautiful font that complements the theme: "${greetingEn} / ${greetingZh}".
              4. STYLE: Cinematic lighting, professional studio photography, vibrant colors, and a polished holiday card aesthetic.
            `,
          },
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: "3:4",
        }
      }
    });

    if (!response.candidates?.[0]?.content?.parts) {
      throw new Error('No image generated');
    }

    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }

    throw new Error('Image data not found in response');
  } catch (error) {
    console.error('Error generating festival card:', error);
    throw error;
  }
}

