import { GoogleGenAI } from "@google/genai";
import { AspectRatio } from "../types";

export async function generateFestivalCard(
  base64Image: string,
  stylePrompt: string,
  aspectRatio: AspectRatio,
  language: 'EN' | 'ZH'
): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const cleanBase64 = base64Image.split(',')[1] || base64Image;

  const greetings = language === 'ZH' 
    ? '恭喜發財 / 新年快樂 / 萬事如意' 
    : 'Happy New Year / Best Wishes / Season\'s Greetings';

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            inlineData: {
              data: cleanBase64,
              mimeType: 'image/jpeg',
            },
          },
          {
            text: `
              ACT AS A WORLD-CLASS DIGITAL ARTIST. 
              TASK: Reconstruct the uploaded photo into a festive masterpiece based on the following style: "${stylePrompt}".

              CRITICAL INSTRUCTIONS:
              1. SUBJECT TRANSFORMATION: Keep all people and pets (cats/dogs). Ensure they are fully integrated into the art style.
              2. OBJECT REPLACEMENT (MANDATORY): If the subjects are holding mundane objects like boxes, folders, plastic bags, or office supplies, YOU MUST REMOVE THEM. 
                 Instead, replace them with:
                 - Festive props: A decorative fan, a red envelope (Hongbao), a holiday gift box, or a traditional lantern.
                 - Natural gestures: Hands placed neatly in lap, or hands in a "greeting" (Gongxi) pose.
              3. TEXT INTEGRATION: Incorporate the text "${greetings}" into the design using typography that matches the style (e.g., calligraphy for traditional, neon for pop).
              4. QUALITY: Ensure professional composition, cinematic lighting, and sharp textures. The final output must look like a curated holiday card, not a simple filter.
            `,
          },
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: aspectRatio,
        }
      }
    });

    if (!response.candidates?.[0]?.content?.parts) throw new Error('No content');
    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
    }
    throw new Error('Image data missing');
  } catch (error) {
    console.error('Gemini error:', error);
    throw error;
  }
}

