import { GoogleGenAI } from "@google/genai";
import { AspectRatio } from "../types";

export async function generateFestivalCard(
  base64Image: string,
  festivalPrompt: string,
  stylePrompt: string,
  greetingEn: string,
  greetingZh: string,
  aspectRatio: AspectRatio
): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const cleanBase64 = base64Image.split(',')[1] || base64Image;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            inlineData: {
              data: cleanBase64,
              mimeType: 'image/jpeg',
            },
          },
          {
            text: `
              ACT AS A PREMIER CULTURAL ARTIST AND DIGITAL ILLUSTRATOR.

              THEME: ${festivalPrompt}
              RENDERING STYLE: ${stylePrompt}

              MANDATORY TEXT CONTENT:
              1. "${greetingEn}"
              2. "${greetingZh}"

              STRICT INSTRUCTIONS:
              1. SUBJECT INTEGRITY: Preserve all people and pets (cats/dogs) from the input. Adapt their clothing and features to match the THEME and RENDERING STYLE.
              2. OBJECT REMOVAL & REPLACEMENT: Mundane items (folders, cardboard boxes, plastic bags, office equipment) MUST be removed. Replace them with cultural props (lanterns, gifts, traditional fans) or have subjects pose with empty hands in a festive gesture.
              3. TYPOGRAPHY & SPELLING (CRITICAL): 
                 - Render the MANDATORY TEXT CONTENT exactly as written. 
                 - DO NOT ALTER SPELLING. 
                 - The text must be legible and integrated artistically (e.g., gold foil effect, calligraphy, neon sign) matching the RENDERING STYLE.
                 - Both languages must be present and distinct.
              4. CULTURAL ACCURACY: Ensure attire and backgrounds are authentic to the selected festival culture.
              5. QUALITY: High-quality composition, cinematic lighting, and sharp artistic textures.
            `,
          },
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: aspectRatio,
        }
      }
    });

    if (!response.candidates?.[0]?.content?.parts) throw new Error('No content');
    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
    }
    throw new Error('Image data missing');
  } catch (error) {
    console.error('Gemini error:', error);
    throw error;
  }
}

