  greetingZh: string,
  aspectRatio: AspectRatio
): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const cleanBase64 = base64Image.split(',')[1] || base64Image;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            inlineData: {
              data: cleanBase64,
              mimeType: 'image/jpeg',
            },
          },
          {
            text: `
              ACT AS A PREMIER CULTURAL ARTIST AND DIGITAL ILLUSTRATOR.

              THEME (CULTURAL CONTEXT): ${festivalPrompt}
              RENDERING STYLE (ARTISTIC MEDIUM): ${stylePrompt}

              MANDATORY TEXT CONTENT:
              1. "${greetingEn}"
              2. "${greetingZh}"

              STRICT INSTRUCTIONS:
              1. SUBJECT INTEGRITY & ATTIRE: 
                 - Preserve the facial features of all people and pets from the input. 
                 - **CRITICAL**: Change their clothing to match the THEME (e.g., Kimono for Japanese New Year, Dirndl/Lederhosen for Oktoberfest, Saree for Diwali).
                 - Do NOT let the RENDERING STYLE override the cultural clothing (e.g., if Style is Manga but Theme is Oktoberfest, draw subjects in Lederhosen, NOT Japanese school uniforms).

              2. BACKGROUND & PROPS:
                 - Remove mundane office/home clutter.
